  { path: '/donate', label: 'Philanthropy' },
  { path: '/gallery', label: 'Gallery' },
  { path: '/reach-out', label: 'Contact' },
]

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false)
  const [mobileOpen, setMobileOpen] = useState(false)
  const [activeMega, setActiveMega] = useState(null)
  const megaRef = useRef(null)
  const location = useLocation()

  /* Scroll detection */
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40)
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  /* Close mobile menu on route change */
  useEffect(() => {
    setMobileOpen(false)
    setActiveMega(null)
  }, [location.pathname])

  /* Close mega menu on outside click */
  useEffect(() => {
    const handler = (e) => {
      if (megaRef.current && !megaRef.current.contains(e.target)) {
        setActiveMega(null)
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [])

  const handleMegaToggle = (label) => {
    setActiveMega(activeMega === label ? null : label)
  }

  return (
    <header
      className={`navbar ${scrolled ? 'navbar--scrolled' : ''}`}
      role="banner"
    >
      <nav className="navbar__inner container" aria-label="Main navigation" ref={megaRef}>
        {/* Logo */}
        <Link to="/" className="navbar__logo" aria-label="Prayas Public School Home">
          <span className="navbar__logo-icon">P</span>
          <div className="navbar__logo-text">
            <span className="navbar__logo-name">Prayas</span>
            <span className="navbar__logo-tagline">Public School</span>
          </div>
        </Link>

        {/* Desktop Nav */}
        <ul className="navbar__links" role="menubar">
          {NAV_LINKS.map((link) => (
            <li
              key={link.label}
              className={`navbar__item ${link.mega ? 'navbar__item--has-mega' : ''}`}
              role="none"
            >
              {link.mega ? (
                <>
                  <button
                    className={`navbar__link navbar__link--mega ${
                      location.pathname === link.path ? 'navbar__link--active' : ''
                    }`}
                    onClick={() => handleMegaToggle(link.label)}
                    aria-expanded={activeMega === link.label}
                    aria-haspopup="true"
                    role="menuitem"
                  >
                    {link.label}
                    <svg className={`navbar__chevron ${activeMega === link.label ? 'navbar__chevron--open' : ''}`} width="10" height="6" viewBox="0 0 10 6" fill="none">
                      <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                  </button>

                  <AnimatePresence>
                    {activeMega === link.label && (
                      <motion.div
                        className="mega-menu"
                        initial={{ opacity: 0, y: 8, scale: 0.98 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 8, scale: 0.98 }}
                        transition={{ duration: 0.25, ease: [0.25, 0.1, 0.25, 1] }}
                        role="menu"
                      >
                        <div className="mega-menu__grid">
                          {link.children.map((child) => (
                            <Link
                              key={child.path + child.label}
                              to={child.path}
                              className="mega-menu__item"
                              role="menuitem"
                              onClick={() => setActiveMega(null)}
                            >
                              <span className="mega-menu__item-label">{child.label}</span>
                              <span className="mega-menu__item-desc">{child.desc}</span>
                            </Link>
                          ))}
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </>
              ) : (
                <NavLink
                  to={link.path}
                  className={({ isActive }) =>
                    `navbar__link ${isActive ? 'navbar__link--active' : ''}`
                  }
                  role="menuitem"
                >
                  {link.label}
                </NavLink>
              )}
            </li>
          ))}
        </ul>

        {/* CTA */}
        <Link to="/admissions#enquiry" className="btn btn--primary navbar__cta">
          Apply Now
        </Link>

        {/* Mobile Toggle */}
        <button
          className={`navbar__hamburger ${mobileOpen ? 'navbar__hamburger--open' : ''}`}
          onClick={() => setMobileOpen(!mobileOpen)}
          aria-label={mobileOpen ? 'Close menu' : 'Open menu'}
          aria-expanded={mobileOpen}
        >
          <span />
          <span />
          <span />
        </button>
      </nav>

      {/* Mobile Menu */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            className="mobile-menu"
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.35, ease: [0.25, 0.1, 0.25, 1] }}
          >
            <ul className="mobile-menu__links">
              {NAV_LINKS.map((link) => (
                <li key={link.label}>
                  <NavLink
                    to={link.path}
                    className={({ isActive }) =>
                      `mobile-menu__link ${isActive ? 'mobile-menu__link--active' : ''}`
                    }
                  >
                    {link.label}
                  </NavLink>
                  {link.children && (
                    <ul className="mobile-menu__sub">
                      {link.children.map((child) => (
                        <li key={child.path + child.label}>
                          <NavLink to={child.path} className="mobile-menu__sub-link">
                            {child.label}
                          </NavLink>
                        </li>
                      ))}
                    </ul>
                  )}
                </li>
              ))}
              <li>
                <Link to="/admissions#enquiry" className="btn btn--primary mobile-menu__cta">
                  Apply Now
                </Link>
              </li>
            </ul>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  )
}

import { motion } from 'framer-motion'

const pageVariants = {
