function Magnetic({ children }) {
  const ref = useRef(null)
  const [position, setPosition] = useState({ x: 0, y: 0 })

  const handleMouse = (e) => {
    const { clientX, clientY } = e
    const { height, width, left, top } = ref.current.getBoundingClientRect()
    const middleX = clientX - (left + width / 2)
    const middleY = clientY - (top + height / 2)
    setPosition({ x: middleX * 0.2, y: middleY * 0.2 })
  }

  const reset = () => {
    setPosition({ x: 0, y: 0 })
  }

  const { x, y } = position
  return (
    <motion.div
      ref={ref}
      onMouseMove={handleMouse}
      onMouseLeave={reset}
      animate={{ x, y }}
      transition={{ type: "spring", stiffness: 150, damping: 15, mass: 0.1 }}
    >
      {children}
    </motion.div>
  )
}

function ImageReveal({ src, alt, className, delay = 0 }) {
  return (
    <motion.div
      className={className}
      style={{ overflow: 'hidden', position: 'relative', borderRadius: '12px' }}
      initial={{ clipPath: 'inset(100% 0 0 0)' }}
      whileInView={{ clipPath: 'inset(0% 0 0 0)' }}
      viewport={{ once: true, margin: '-50px' }}
      transition={{ duration: 1.4, ease: [0.76, 0, 0.24, 1], delay }}
    >
      <motion.img
        src={src}
        alt={alt}
        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
        initial={{ scale: 1.5 }}
        whileInView={{ scale: 1 }}
        viewport={{ once: true, margin: '-50px' }}
        transition={{ duration: 1.4, ease: [0.76, 0, 0.24, 1], delay }}
      />
    </motion.div>
  )
}

function AnimatedSnakeLine({ scrollProgress }) {
  const pathLength = useSpring(scrollProgress, { damping: 50, stiffness: 200 })

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '150%', pointerEvents: 'none', zIndex: 0 }}>
      {/* 
        This SVG spans the Hero section and leaks down perfectly.
        non-scaling-stroke keeps our 24px stroke absolutely crisp regardless of screen stretch.
      */}
      <svg 
        viewBox="0 0 1000 600"
        preserveAspectRatio="none"
        style={{ width: '100%', height: '100%', overflow: 'visible' }}
      >
        <motion.path
          d="M -100 400 C 200 100, 400 700, 600 300 S 800 500, 1100 200"
          fill="none"
          stroke="var(--color-primary)"
          strokeWidth="32"
          strokeLinecap="round"
          vectorEffect="non-scaling-stroke"
          style={{ pathLength, opacity: 0.8 }}
        />
        <motion.path
          d="M -100 300 C 300 -100, 700 800, 1100 100"
          fill="none"
          stroke="var(--color-primary)" 
          strokeWidth="12"
          strokeLinecap="round"
          vectorEffect="non-scaling-stroke"
          style={{ pathLength, opacity: 0.3 }}
        />
      </svg>
    </div>
  )
}

